function collectRedemption() external {
    require((lastRedeemed[msg.sender].add(redemption_delay)) <= block.number, "Must wait for redemption_delay blocks before collecting redemption");
    bool sendFXS = false;
    bool sendCollateral = false;
    uint FXSAmount = 0;
    uint CollateralAmount = 0;

    // Use Checks-Effects-Interactions pattern
    if(redeemFXSBalances[msg.sender] > 0){
        FXSAmount = redeemFXSBalances[msg.sender];
        redeemFXSBalances[msg.sender] = 0;
        unclaimedPoolFXS = unclaimedPoolFXS.sub(FXSAmount);

        sendFXS = true;
    }

    if(redeemCollateralBalances[msg.sender] > 0){
        CollateralAmount = redeemCollateralBalances[msg.sender];
        redeemCollateralBalances[msg.sender] = 0;
        unclaimedPoolCollateral = unclaimedPoolCollateral.sub(CollateralAmount);

        sendCollateral = true;
    }

    if(sendFXS){
        TransferHelper.safeTransfer(address(FXS), msg.sender, FXSAmount);
    }
    if(sendCollateral){
        TransferHelper.safeTransfer(address(collateral_token), msg.sender, CollateralAmount);
    }
}

function _calculateSpokeBalance(
    IAaveV4Spoke spoke_,
    address priceOracleMiddleware_
) private view returns (int256) {
    int256 spokeBalance;
    uint256 reserveCount = spoke_.getReserveCount();
    address plasmaVault = address(this);

    IAaveV4Spoke.Reserve memory reserve;
    bytes32 assetSubstrate;

    // Reserves are indexed sequentially from 0 in Aave V4
    for (uint256 r; r < reserveCount; ++r) {
        reserve = spoke_.getReserve(r);

        // Skip reserves whose underlying asset is not a granted substrate.
        // Supply/Borrow fuses enforce asset substrate validation, so the vault
        // cannot hold positions in reserves with non-granted assets.
        assetSubstrate = AaveV4SubstrateLib.encodeAsset(reserve.underlying);
        if (!PlasmaVaultConfigLib.isMarketSubstrateGranted(MARKET_ID, assetSubstrate)) {
            continue;
        }

        spokeBalance += _calculateReserveBalance(spoke_, r, reserve.underlying, plasmaVault, priceOracleMiddleware_);
    }

    return spokeBalance;
}

function getBondingCheckpointAt(address _account, uint256 _round)
        internal
        view
        returns (BondingCheckpoint storage)
    {
        if (_round > clock() + 1) {
            revert FutureLookup(_round, clock() + 1);
        }

        BondingCheckpointsByRound storage checkpoints = bondingCheckpoints[_account];

        // Most of the time we will be calling this for a transcoder which checkpoints on every round through reward().
        // On those cases we will have a checkpoint for exactly the round we want, so optimize for that.
        BondingCheckpoint storage bond = checkpoints.data[_round];
        if (bond.bondedAmount > 0) {
            return bond;
        }

        uint256 startRoundIdx = checkpoints.startRounds.findLowerBound(_round);
        if (startRoundIdx == checkpoints.startRounds.length) {
            // No checkpoint at or before _round, so return the zero BondingCheckpoint value. This also happens if there
            // are no checkpoints for _account. The voting power will be zero until the first checkpoint is made.
            return bond;
        }

        uint256 startRound = checkpoints.startRounds[startRoundIdx];
        return checkpoints.data[startRound];
    }

function rawCall(
    uint256 _gas,
    address _address,
    uint256 _value,
    bytes calldata _data,
    bool _isSystem
) internal returns (bool success) {
    if (_value == 0) {
        _loadFarCallABIIntoActivePtr(_gas, _data, false, _isSystem);

        address callAddr = RAW_FAR_CALL_BY_REF_CALL_ADDRESS;
        assembly {
            success := call(_address, callAddr, 0, 0, 0xFFFF, 0, 0)
        }
    } else {
        _loadFarCallABIIntoActivePtr(_gas, _data, false, true);

        // If there is provided `msg.value` call the `MsgValueSimulator` to forward ether.
        address msgValueSimulator = MSG_VALUE_SYSTEM_CONTRACT;
        address callAddr = SYSTEM_CALL_BY_REF_CALL_ADDRESS;
        // We need to supply the mask to the MsgValueSimulator to denote
        // that the call should be a system one.
        uint256 forwardMask = _isSystem ? MSG_VALUE_SIMULATOR_IS_SYSTEM_BIT : 0;

        assembly {
            success := call(msgValueSimulator, callAddr, _value, _address, 0xFFFF, forwardMask, 0)
        }
    }
}

function _display(uint256 value, bytes memory mod) private pure returns (string memory) {
    if (mod.length == 0) {
        return strings.toString(value);
    } else if (mod[0] == "d" && mod.length <= 4) {
        // Max decimals is 256
        uint8 decimals = uint8(strings.parseUint(string(_readSlice(mod, 1, mod.length - 1))));
        string memory integer = strings.toString(value / 10 ** decimals);

        // Get decimal part and pad with zeroes
        string memory remainder = strings.toString(value % 10 ** decimals);

        while (bytes(remainder).length < decimals) {
            remainder = string.concat("0", remainder);
        }

        // Get expected remainder length without trailing zeroes
        uint256 len = decimals;
        while (len > 1 && bytes(remainder)[len - 1] == "0") {
            len--;
        }

        // Set new length to remove trailing zeroes
        assembly {
            mstore(remainder, len)
        }

        return string.concat(integer, ".", remainder);
    } else {
        revert(_formatError("_display(uint256,bytes)", "Unsupported modifier"));
    }
}

function _validateExtendedVoteSig(
    uint256 proposalId,
    uint8 support,
    address voter,
    string memory reason,
    bytes memory params,
    bytes memory signature
) internal virtual override returns (bool) {
    if (
        SignatureChecker.isValidSignatureNow(
            voter,
            _hashTypedDataV4(
                keccak256(
                    abi.encode(
                        EXTENDED_BALLOT_TYPEHASH,
                        proposalId,
                        support,
                        voter,
                        nonces(voter, uint192(proposalId)),
                        keccak256(bytes(reason)),
                        keccak256(params)
                    )
                )
            ),
            signature
        )
    ) {
        _useNonce(voter, uint192(proposalId));
        return true;
    } else {
        return super._validateExtendedVoteSig(proposalId, support, voter, reason, params, signature);
    }
}

function checkCallback(
  bytes[] memory values,
  bytes memory lookupData
) external view override returns (bool, bytes memory) {
  bytes[] memory filteredValues = new bytes[](values.length);
  uint256 count = 0;
  for (uint256 i = 0; i < values.length; i++) {
    Report memory report = _getReport(values[i]);
    string memory feedId = _bytes32ToHexString(abi.encodePacked(report.feedId));
    Feed memory feed = s_feedMapping[feedId];
    if (
      (report.observationsTimestamp - feed.observationsTimestamp > feed.stalenessSeconds) ||
      deviationExceedsThreshold(feed.price, report.price, feed.deviationPercentagePPM)
    ) {
      filteredValues[count] = values[i];
      count++;
    }
  }

  // Adjusts the length of the filteredValues array to `count` such that it
  // does not have extra empty slots, in case some items were filtered.
  assembly {
    mstore(filteredValues, count)
  }

  bytes memory performData = abi.encode(filteredValues, lookupData);
  return (filteredValues.length > 0, performData);
}

function toSpec(string memory cronString) internal pure returns (Spec memory) {
  strings.slice memory space = strings.toSlice(" ");
  strings.slice memory cronSlice = strings.toSlice(cronString);
  if (cronSlice.count(space) != 4) {
    revert InvalidSpec("4 spaces required");
  }
  strings.slice memory minuteSlice = cronSlice.split(space);
  strings.slice memory hourSlice = cronSlice.split(space);
  strings.slice memory daySlice = cronSlice.split(space);
  strings.slice memory monthSlice = cronSlice.split(space);
  // DEV: dayOfWeekSlice = cronSlice
  // The cronSlice now contains the last section of the cron job,
  // which corresponds to the day of week
  if (
    minuteSlice.len() == 0 ||
    hourSlice.len() == 0 ||
    daySlice.len() == 0 ||
    monthSlice.len() == 0 ||
    cronSlice.len() == 0
  ) {
    revert InvalidSpec("some fields missing");
  }
  return
    validate(
      Spec({
        minute: sliceToField(minuteSlice),
        hour: sliceToField(hourSlice),
        day: sliceToField(daySlice),
        month: sliceToField(monthSlice),
        dayOfWeek: sliceToField(cronSlice)
      })
    );
}

function addHarvestJob(
  bool active,
  address alchemist,
  address yieldToken,
  uint256 minimumHarvestAmount,
  uint256 minimumDelay,
  uint256 slippageBps
) external onlyOwner {
  IAlchemistV2.YieldTokenParams memory ytp = IAlchemistV2(alchemist).getYieldTokenParameters(yieldToken);
  if (!ytp.enabled) {
    revert YieldTokenDisabled();
  }

  if (slippageBps > SLIPPAGE_PRECISION) {
    revert IllegalArgument();
  }

  harvestJobs[yieldToken] = HarvestJob(
    active,
    alchemist,
    yieldToken,
    block.timestamp,
    minimumHarvestAmount,
    minimumDelay,
    slippageBps
  );

  emit SetHarvestJob(active, alchemist, yieldToken, minimumHarvestAmount, minimumDelay, slippageBps);

  // Only add the yield token to the list if it doesnt exist yet.
  for (uint256 i = 0; i < yieldTokens.length; i++) {
    if (yieldTokens[i] == yieldToken) {
      return;
    }
  }
  yieldTokens.push(yieldToken);
}

