function _payback(
    address _market,
    address _tokenAddr,
    uint256 _amount,
    uint256 _rateMode,
    address _from,
    address _onBehalf
) internal returns (uint256, bytes memory) {
    // default to onBehalf of user's wallet
    if (_onBehalf == address(0)) {
        _onBehalf = address(this);
    }
    ILendingPoolV2 lendingPool = getLendingPool(_market);
    uint256 maxDebt = getWholeDebt(_market, _tokenAddr, _rateMode, _onBehalf);
    _amount = _amount > maxDebt ? maxDebt : _amount;

    _tokenAddr.pullTokensIfNeeded(_from, _amount);
    _tokenAddr.approveToken(address(lendingPool), _amount);

    uint256 tokensBefore = _tokenAddr.getBalance(address(this));

    lendingPool.repay(_tokenAddr, _amount, _rateMode, _onBehalf);

    uint256 tokensAfter = _tokenAddr.getBalance(address(this));

    // send back any leftover tokens that weren't used in the repay
    _tokenAddr.withdrawTokens(_from, tokensAfter);

    bytes memory logData = abi.encode(_market, _tokenAddr, _amount, _rateMode, _from, _onBehalf);
    return (tokensBefore - tokensAfter, logData);
}

function _liquidate(Params memory _params) internal returns (uint256, bytes memory) {
    if (_params.swapAmount == 0) revert();

    address curveUsdSwapper = registry.getAddr(DFSIds.CURVE_SWAPPER);

    uint256[] memory swapData = _setupCurvePath(
        curveUsdSwapper,
        _params.additionalData,
        _params.swapAmount,
        _params.minAmount,
        _params.gasUsed,
        _params.dfsFeeDivider
    );

    ICrvUsdController(_params.controllerAddress)
        .liquidate_extended(
            address(this),
            _params.minCrvUsdExpected,
            _params.percentage,
            false,
            curveUsdSwapper,
            swapData
        );

    // cleanup after the callback if any funds are left over
    CurveUsdSwapper(curveUsdSwapper).withdrawAll(_params.controllerAddress);

    // send funds to user
    _sendLeftoverFunds(_params.controllerAddress, _params.to);

    return (_params.percentage, abi.encode(_params));
}

function callback_liquidate(
    address _user,
    uint256,
    uint256,
    uint256,
    uint256[] memory swapData
) external returns (CallbackData memory cb) {
    address controllerAddr = msg.sender;

    // check if controller is valid
    if (!isControllerValid(controllerAddr)) revert CurveUsdInvalidController();

    // we get _ethCollAmount in tokens from curve
    address collToken = ICrvUsdController(controllerAddr).collateral_token();

    // if we want to sell the whole coll amount we take the whole balance
    if (swapData[0] == type(uint256).max) {
        swapData[0] = IERC20(collToken).balanceOf(address(this));
    }

    uint256 swappedAmount = _curveSwap(_user, swapData, collToken, true);

    // how many crvUsd we got after the trade that will be the repay amount
    cb.stablecoins = swappedAmount;
    IERC20(CRVUSD_TOKEN_ADDR).safeApprove(controllerAddr, cb.stablecoins);

    // approve to pick up extra coll and send to user
    cb.collateral = IERC20(collToken).balanceOf(address(this));
    IERC20(collToken).safeApprove(controllerAddr, cb.collateral);
}

function _payback(Params memory _params) internal returns (uint256, bytes memory) {
    address assetAddr = IEVault(_params.vault).asset();

    if (_params.account == address(0)) {
        _params.account = address(this);
    }

    bool maxPayback;

    uint256 currentAccountDebt = IEVault(_params.vault).debtOf(_params.account);
    if (_params.amount > currentAccountDebt) {
        _params.amount = currentAccountDebt;
        maxPayback = true;
    }

    assetAddr.pullTokensIfNeeded(_params.from, _params.amount);
    assetAddr.approveToken(_params.vault, _params.amount);

    _params.amount = IEVault(_params.vault).repay(_params.amount, _params.account);

    if (maxPayback) {
        // Actual EVC function is named `call`, so it is safe to disable rule
        // forge-lint: disable-start(unchecked-call)
        IEVC(EVC_ADDR)
            .call(
                _params.vault,
                _params.account,
                0,
                abi.encodeCall(IRiskManager.disableController, ())
            );
        // forge-lint: disable-end(unchecked-call)
    }

    return (_params.amount, abi.encode(_params));
}

function _supply(
    address _market,
    uint256 _amount,
    address _from,
    uint16 _assetId,
    address _onBehalf
) internal returns (uint256, bytes memory) {
    ISparkPool lendingPool = getSparkLendingPool(_market);
    address tokenAddr = lendingPool.getReserveAddressById(_assetId);

    // if amount is set to max, take the whole _from balance
    if (_amount == type(uint256).max) {
        _amount = tokenAddr.getBalance(_from);
    }

    // default to onBehalf of user's wallet
    if (_onBehalf == address(0)) {
        _onBehalf = address(this);
    }

    // pull tokens to user's wallet so we can supply
    tokenAddr.pullTokensIfNeeded(_from, _amount);

    // approve spark pool to pull tokens
    tokenAddr.approveToken(address(lendingPool), _amount);

    lendingPool.supply(tokenAddr, _amount, _onBehalf, SPARK_REFERRAL_CODE);

    bytes memory logData = abi.encode(_market, tokenAddr, _amount, _from, _onBehalf);
    return (_amount, logData);
}

function _uniCreatePosition(Params memory _inputData)
        internal
        returns (uint256 tokenId, bytes memory logData)
    {
        // fetch tokens from address;
        uint256 amount0Pulled =
            _inputData.token0.pullTokensIfNeeded(_inputData.from, _inputData.amount0Desired);
        uint256 amount1Pulled =
            _inputData.token1.pullTokensIfNeeded(_inputData.from, _inputData.amount1Desired);

        // approve positionManager so it can pull tokens
        _inputData.token0.approveToken(address(positionManager), amount0Pulled);
        _inputData.token1.approveToken(address(positionManager), amount1Pulled);

        _inputData.amount0Desired = amount0Pulled;
        _inputData.amount1Desired = amount1Pulled;

        uint128 liquidity;
        uint256 amount0;
        uint256 amount1;
        (tokenId, liquidity, amount0, amount1) = _uniMint(_inputData);

        //send leftovers
        _inputData.token0.withdrawTokens(_inputData.from, _inputData.amount0Desired - amount0);
        _inputData.token1.withdrawTokens(_inputData.from, _inputData.amount1Desired - amount1);

        logData = abi.encode(_inputData, tokenId, liquidity, amount0, amount1);
    }

