function _refund(
    IERC20 token,
    uint256 tokenPrice,
    uint256 actualGasCost,
    uint256 actualUserOpFeePerGas,
    address prefunder,
    uint256 prefundAmount,
    bytes calldata prefundContext
) internal virtual override returns (bool refunded, uint256 actualAmount) {
    address userOpSender = address(bytes20(prefundContext[0x00:0x14]));

    if (prefunder != userOpSender) {
        actualAmount = _erc20Cost(actualGasCost, actualUserOpFeePerGas, tokenPrice);
        if (token.trySafeTransferFrom(userOpSender, address(this), actualAmount)) {
            // The paymaster gets the funds first, so in case of a failure, the guarantor absorbs the cost.
            return (token.trySafeTransfer(prefunder, prefundAmount), actualAmount);
        }
    }
    return
        super._refund(
            token,
            tokenPrice,
            actualGasCost,
            actualUserOpFeePerGas,
            prefunder,
            prefundAmount,
            prefundContext
        );
}

function getBytesTransiently() public view returns (bytes memory result) {
    uint256 dataLength;
    // fetch data length from first slot
    assembly {
        dataLength := tload(0)
    }
    // find out how many full size chunks there are
    uint256 chunks = dataLength / 32;
    uint256 i = 1;
    // concat each full size chunk to the result
    for (i; i <= chunks; ++i) {
        bytes32 chunk;
        assembly {
            chunk := tload(i)
        }
        result = bytes.concat(result, chunk);
    }
    uint256 leftover = dataLength % 32;
    // create a bytes consisting only of the leftover information
    if (leftover > 0) {
        bytes32 lastChunk;
        assembly {
            lastChunk := tload(i)
        }
        bytes memory cutChunk = new bytes(leftover);
        for (uint256 j = 0; j < leftover; j++) {
            cutChunk[j] = bytes1(bytes32(lastChunk << (j * 8))); // Shift the bytes32 by 8 bits each time
        }

        result = bytes.concat(result, cutChunk);
    }
}

function _getUserReserveData(address _spoke, address _user, uint256 _reserveId)
        internal
        view
        returns (UserReserveData memory)
    {
        ISpoke spoke = ISpoke(_spoke);
        ISpoke.Reserve memory reserve = spoke.getReserve(_reserveId);
        ISpoke.DynamicReserveConfig memory config = spoke.getDynamicReserveConfig(
            _reserveId, spoke.getUserPosition(_reserveId, _user).dynamicConfigKey
        );

        (uint256 drawn, uint256 premium) = spoke.getUserDebt(_reserveId, _user);
        (bool isUsingAsCollateral, bool isBorrowing) = spoke.getUserReserveStatus(_reserveId, _user);

        return UserReserveData({
            reserveId: _reserveId,
            assetId: reserve.assetId,
            underlying: reserve.underlying,
            supplied: spoke.getUserSuppliedAssets(_reserveId, _user),
            drawn: drawn,
            premium: premium,
            totalDebt: drawn + premium,
            collateralFactor: config.collateralFactor,
            maxLiquidationBonus: config.maxLiquidationBonus,
            liquidationFee: config.liquidationFee,
            isUsingAsCollateral: isUsingAsCollateral,
            isBorrowing: isBorrowing
        });
    }

